# Dictionaries: the shape of every API message
message = {
    "role": "user",
    "content": "What is agentic AI?"
}

# Accessing nested data from an API response
response = {
    "id": "msg_abc123",
    "content": [
        {"type": "text", "text": "Agentic AI refers to..."}
    ],
    "model": "claude-sonnet-4-20250514",
    "usage": {"input_tokens": 12, "output_tokens": 85}
}

# Get the text from the first content block
answer = response["content"][0]["text"]
print(f"Used {response['usage']['input_tokens']} input tokens")

# List comprehension: filter content blocks by type
text_blocks = [block["text"] for block in response["content"] if block["type"] == "text"]

# Another common pattern: building a conversation history
conversation = [
    {"role": "user", "content": "Hi"},
    {"role": "assistant", "content": "Hello! How can I help?"},
    {"role": "user", "content": "Tell me about agents."},
]
